/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements the NotificationAdapter interface with:
 * - Configurable webhook URL
 * - JSON payload formatting
 * - Configurable HTTP transport abstraction (mirrors email adapter pattern)
 *
 * In production, provide a real WebhookTransport (e.g., fetch/axios-based).
 * For testing, use the built-in InMemoryWebhookTransport.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a formatted webhook request ready for sending.
 */
export interface WebhookRequest {
  url: string;
  headers: Record<string, string>;
  body: string;
}

/**
 * Transport interface for sending webhook HTTP requests.
 * Implement this to integrate with fetch, axios, or any HTTP client.
 */
export interface WebhookTransport {
  post(request: WebhookRequest): Promise<{ statusCode: number; accepted: boolean }>;
}

/**
 * In-memory transport for testing. Records all sent webhook requests.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  readonly sent: WebhookRequest[] = [];

  async post(request: WebhookRequest): Promise<{ statusCode: number; accepted: boolean }> {
    this.sent.push(request);
    return { statusCode: 200, accepted: true };
  }

  clear(): void {
    this.sent.length = 0;
  }
}

/**
 * A transport that always fails, for testing error paths.
 */
export class FailingWebhookTransport implements WebhookTransport {
  constructor(private errorMessage = 'Connection refused') {}

  async post(_request: WebhookRequest): Promise<{ statusCode: number; accepted: boolean }> {
    throw new Error(this.errorMessage);
  }
}

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookAdapterConfig {
  url: string;
  secret?: string;
  transport: WebhookTransport;
}

/**
 * Format a notification payload into a JSON webhook request body.
 */
function formatWebhookBody(payload: NotificationPayload): Record<string, unknown> {
  return {
    event: payload.type,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    priority: payload.priority,
    metadata: payload.metadata ?? {},
    timestamp: new Date().toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');

  constructor(private config: WebhookAdapterConfig) {}

  /**
   * Build the webhook request from a notification payload.
   */
  buildRequest(payload: NotificationPayload): WebhookRequest {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    if (this.config.secret) {
      headers['X-Webhook-Secret'] = this.config.secret;
    }

    return {
      url: this.config.url,
      headers,
      body: JSON.stringify(formatWebhookBody(payload)),
    };
  }

  /**
   * Send a webhook notification.
   *
   * 1. Formats the payload as JSON
   * 2. Builds the HTTP request with headers
   * 3. POSTs via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const notificationId = payload.metadata?.notificationId ?? 'unknown';

    try {
      const request = this.buildRequest(payload);

      this.logger.info(
        `Sending webhook to ${request.url} for notification ${notificationId}`,
      );

      const result = await this.config.transport.post(request);

      this.logger.info(
        `Webhook sent successfully: statusCode=${result.statusCode}, notificationId=${notificationId}`,
      );

      return {
        success: result.accepted,
        notificationId,
        channel: 'webhook',
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send webhook for notification ${notificationId}: ${message}`);

      return {
        success: false,
        notificationId,
        channel: 'webhook',
        error: message,
      };
    }
  }
}

