  describe('buildRequest', () => {
    it('formats payload as JSON with correct URL', () => {
      const request = adapter.buildRequest(makePayload());

      expect(request.url).toBe('https://hooks.example.com/notify');
      expect(request.headers['Content-Type']).toBe('application/json');

      const body = JSON.parse(request.body);
      expect(body.event).toBe('order:confirmation');
      expect(body.recipient).toBe('user-123');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toBe('Your order has been placed. Items: Widget x2. Total: $20.00');
      expect(body.channel).toBe('webhook');
      expect(body.priority).toBe('normal');
      expect(body.metadata.orderId).toBe('order-1');
      expect(body.timestamp).toBeDefined();
    });

    it('includes secret header when configured', () => {
      const request = adapter.buildRequest(makePayload());
      expect(request.headers['X-Webhook-Secret']).toBe('test-secret');
    });

    it('omits secret header when not configured', () => {
      const noSecretAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        transport,
      });
      const request = noSecretAdapter.buildRequest(makePayload());
      expect(request.headers['X-Webhook-Secret']).toBeUndefined();
    });

    it('includes empty metadata when none provided', () => {
      const payload = makePayload({ metadata: undefined });
      const request = adapter.buildRequest(payload);
      const body = JSON.parse(request.body);
      expect(body.metadata).toEqual({});
    });

    it('formats all notification types', () => {
      const types = [
        'order:confirmation',
        'order:status-update',
        'user:welcome',
        'user:profile-updated',
