        const request = adapter.buildRequest(makePayload({ type }));
        const body = JSON.parse(request.body);
        expect(body.event).toBe(type);
      }
    });
  });

  describe('send', () => {
    it('sends webhook and returns success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
