    it('returns failure when transport throws', async () => {
      const failAdapter = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        transport: new FailingWebhookTransport('Connection refused'),
      });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(result.channel).toBe('webhook');
    });

    it('uses notificationId from metadata', async () => {
      const payload = makePayload({
        metadata: { notificationId: 'custom-id' },
      });
      const result = await adapter.send(payload);
      expect(result.notificationId).toBe('custom-id');
    });

    it('falls back to unknown when no notificationId in metadata', async () => {
      const payload = makePayload({ metadata: undefined });
      const result = await adapter.send(payload);
      expect(result.notificationId).toBe('unknown');
    });

    it('sends multiple webhooks independently', async () => {
      await adapter.send(makePayload({ recipient: 'user-1' }));
      await adapter.send(makePayload({ recipient: 'user-2' }));

      expect(transport.sent).toHaveLength(2);
      const body1 = JSON.parse(transport.sent[0]!.body);
      const body2 = JSON.parse(transport.sent[1]!.body);
      expect(body1.recipient).toBe('user-1');
      expect(body2.recipient).toBe('user-2');
    });

    it('preserves all payload fields in request body', async () => {
      const payload = makePayload({
        type: 'order:status-update',
        subject: 'Status Changed',
        body: 'Order updated',
        priority: 'high',
        metadata: { orderId: 'order-2', newStatus: 'shipped', notificationId: 'notif-0005' },
      });
      await adapter.send(payload);

      const body = JSON.parse(transport.sent[0]!.body);
      expect(body.event).toBe('order:status-update');
      expect(body.subject).toBe('Status Changed');
      expect(body.body).toBe('Order updated');
      expect(body.priority).toBe('high');
      expect(body.metadata.orderId).toBe('order-2');
      expect(body.metadata.newStatus).toBe('shipped');
    });
  });

  describe('InMemoryWebhookTransport', () => {
    it('records sent requests', async () => {
      const t = new InMemoryWebhookTransport();
      const request = adapter.buildRequest(makePayload());

      const r1 = await t.post(request);
