    });

    it('clears sent requests', async () => {
      const t = new InMemoryWebhookTransport();
      await t.post(adapter.buildRequest(makePayload()));
      t.clear();
      expect(t.sent).toHaveLength(0);
    });
  });

  describe('FailingWebhookTransport', () => {
    it('throws with configured error message', async () => {
      const t = new FailingWebhookTransport('Custom error');
      const request = adapter.buildRequest(makePayload());
      await expect(t.post(request)).rejects.toThrow('Custom error');
    });

    it('uses default error message when none provided', async () => {
      const t = new FailingWebhookTransport();
      const request = adapter.buildRequest(makePayload());
      await expect(t.post(request)).rejects.toThrow('Connection refused');
    });
  });

  describe('integration with NotificationService pattern', () => {
    it('conforms to NotificationAdapter interface', () => {
      expect(typeof adapter.channel).toBe('string');
      expect(typeof adapter.send).toBe('function');
    });
  });
});
